function getApiBaseUrl(){const e=window.MAGALU_RUNTIME_CONFIG&&window.MAGALU_RUNTIME_CONFIG.apiBaseUrl;return e?e.replace(/\/$/,""):""}function buildApiUrl(e){const t=e.startsWith("/")?e:`/${e}`,n=getApiBaseUrl();return n?`${n}${t}`:t}function getAppRootUrl(){const e=new Set(["login","teste","agenda","feed","scanner","scanner-kit","quiz"]),t=new URL(window.location.href),n=t.pathname.split("/").filter(Boolean);if(0===n.length)return`${t.origin}/`;let i=[...n];i[i.length-1].includes(".")&&(i=i.slice(0,-1));const r=i[i.length-1];e.has(r)&&(i=i.slice(0,-1));const s=i.length>0?`/${i.join("/")}/`:"/";return`${t.origin}${s}`}function buildAppUrl(e="/"){const t=getAppRootUrl(),n=e.startsWith("/")?e.slice(1):e;return new URL(n,t).toString()}function withApiDefaults(e={}){const t=new Headers(e.headers||{});return t.set("ngrok-skip-browser-warning","true"),{...e,headers:t}}async function parseApiResponse(e){if((e.headers.get("content-type")||"").includes("application/json"))return e.json();const t=await e.text();return{error:t,rawText:t}}window.magaluApi={buildAppUrl:buildAppUrl,buildApiUrl:buildApiUrl,getAppRootUrl:getAppRootUrl,parseApiResponse:parseApiResponse,withApiDefaults:withApiDefaults};